script:
# Validate Hold fields when transitioning to Hold state
if doc.workflow_state == "Hold":
    if not doc.custom_hold_reason:
        frappe.throw("Hold Reason is mandatory when putting a lead on Hold")
    if not doc.custom_hold_until:
        frappe.throw("Hold Until date is mandatory when putting a lead on Hold")

# Validate required fields before moving to Site Visit Scheduled
if doc.workflow_state == "Site Visit Scheduled":
    missing = []
    if not doc.get("custom_k_number"):
        missing.append("K Number")
    if not doc.get("custom_preferred_visit_date"):
        missing.append("Preferred Visit Date")
    if not doc.get("custom_electricity_bill"):
        missing.append("Electricity Bill")
    if not doc.get("custom_qualification_ready"):
        missing.append("Qualification Ready")

    if missing:
        frappe.throw("The following fields are required before moving to 'Site Visit Scheduled':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate scheduled_date when moving to Scheduled state
if doc.workflow_state == "Scheduled":
    if not doc.get("scheduled_date"):
        frappe.throw("Scheduled Date is required before moving to 'Scheduled' state")

# Validate and auto-set start_time when moving to On-Site
if doc.workflow_state == "On-Site":
    # Validate required fields before starting visit
    missing = []
    if not doc.get("assigned_vendor"):
        missing.append("Assigned Vendor")
    if not doc.get("assigned_to"):
        missing.append("Assigned To")

    if missing:
        frappe.throw("The following fields are required before starting the visit:<br><br>" + "<br>".join(f"- {m}" for m in missing))

    # Auto-set start_time
    doc.start_time = frappe.utils.now_datetime()

# Auto-set end_time when moving to Submitted for Review (always update, even on revisit)
if doc.workflow_state == "Submitted for Review":
    doc.end_time = frappe.utils.now_datetime()

# Set reviewer when moving from Submitted for Review
if doc.workflow_state in ["Completed", "Revisit Required"]:
    if not doc.get("reviewer"):
        doc.reviewer = frappe.session.user

    # Set review_decision based on workflow state
    if doc.workflow_state == "Completed":
        doc.review_decision = "Approve"
    elif doc.workflow_state == "Revisit Required":
        doc.review_decision = "Revisit"

# Validate required fields before completion
if doc.workflow_state == "Completed":
    missing = []
    if not doc.get("lead"):
        missing.append("Lead")
    if not doc.get("visit_type"):
        missing.append("Visit Type")

    if missing:
        frappe.throw("The following fields are required before moving to 'Completed':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate required fields before completion
if doc.workflow_state == "Completed":
    missing = []
    if not doc.get("lead"):
        missing.append("Lead")
    if not doc.get("survey_date"):
        missing.append("Survey Date")
    if not doc.get("survey_engineer"):
        missing.append("Survey Engineer")
    if not doc.get("shading"):
        missing.append("Shading")
    if not doc.get("proposed_system_size_kw"):
        missing.append("Proposed System Size (kW)")

    if missing:
        frappe.throw("The following fields are required before moving to 'Completed':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate required fields before moving to Completed state
if doc.workflow_state == "Completed":
    missing = []
    if not doc.get("lead"):
        missing.append("Lead")
    if not doc.get("planned_start"):
        missing.append("Planned Start")
    if not doc.get("status"):
        missing.append("Status")

    if missing:
        frappe.throw("The following fields are required before moving to 'Completed':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate required fields before workflow transitions
if doc.workflow_state in ["Submitted", "Under Review", "Approved"]:
    missing = []
    if not doc.get("lead"):
        missing.append("Lead")
    if not doc.get("scheme"):
        missing.append("Scheme")
    if not doc.get("status"):
        missing.append("Status")

    if missing:
        frappe.throw(f"The following fields are required before moving to '{doc.workflow_state}':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate required fields before workflow transitions
if doc.workflow_state in ["In Progress", "Resolved", "Closed"]:
    missing = []
    if not doc.get("issue_type"):
        missing.append("Issue Type")
    if not doc.get("status"):
        missing.append("Status")

    if missing:
        frappe.throw(f"The following fields are required before moving to '{doc.workflow_state}':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate required fields before moving to Completed state
if doc.workflow_state == "Completed":
    missing = []
    if not doc.get("service_request"):
        missing.append("Service Request")

    if missing:
        frappe.throw("The following fields are required before moving to 'Completed':<br><br>" + "<br>".join(f"- {m}" for m in missing))

# Validate required fields before workflow transitions
if doc.workflow_state in ["Applied", "Feasibility Approved", "Energized"]:
    missing = []
    if not doc.get("lead"):
        missing.append("Lead")
    if not doc.get("discom"):
        missing.append("DISCOM")
    if not doc.get("status"):
        missing.append("Status")

    if missing:
        frappe.throw(f"The following fields are required before moving to '{doc.workflow_state}':<br><br>" + "<br>".join(f"- {m}" for m in missing))
